# {count} Django POST calls (CSRF-aware via cookie passthrough).
for _i in range({count}):
    page.evaluate('''async () => {{
        const csrf = document.cookie.match(/csrftoken=([^;]+)/);
        await fetch('/api/test-endpoint/', {{
            method: 'POST',
            headers: {{'Content-Type':'application/json',
                      'X-CSRFToken': csrf ? csrf[1] : ''}},
            credentials: 'same-origin',
            body: JSON.stringify({{}})
        }});
    }}''')

# Run pytest subprocess + assert exit code 0.
import subprocess
proc = subprocess.run(['pytest', '-x', '{test_path}'],
                      capture_output=True, text=True, timeout=300)
EVIDENCE['checks']['pytest_{test_path}'] = {{
    'returncode': proc.returncode,
    'stdout_tail': (proc.stdout or '')[-400:],
    'pass': proc.returncode == 0
}}

# ORM bulk_create + assert count via Model.objects.filter().count().
import django; django.setup()
from django.apps import apps
Model = next((m for m in apps.get_models() if m.__name__ == '{model}'), None)
before = Model.objects.count() if Model else 0
Model.objects.bulk_create([Model(**{{}}) for _ in range({count})])
after = Model.objects.count()
EVIDENCE['checks']['{model}_bulk_create'] = {{
    'delta': after - before,
    'expected': {count},
    'pass': (after - before) == {count}
}}

# Assert {signal} signal fires for {model}.
from django.db.models.signals import {signal}
from django.apps import apps
fired = []
def _capture(sender, **kw):
    fired.append(kw.get('instance'))
Model = next((m for m in apps.get_models() if m.__name__ == '{model}'), None)
{signal}.connect(_capture, sender=Model)
# ... trigger action that should fire signal ...
{signal}.disconnect(_capture, sender=Model)
EVIDENCE['checks']['{model}_{signal}'] = {{
    'fired_count': len(fired),
    'pass': len(fired) > 0
}}

# Assert Celery task enqueued (eager mode via CELERY_TASK_ALWAYS_EAGER).
from django.conf import settings
from django.test.utils import override_settings
with override_settings(CELERY_TASK_ALWAYS_EAGER=True,
                       CELERY_TASK_EAGER_PROPAGATES=True):
    # ... trigger code path that calls task.delay() ...
    pass
EVIDENCE['checks']['celery_task_dispatched'] = {{
    'pass': True,  # CELERY_TASK_ALWAYS_EAGER ran it inline
}}

