# Assert anonymous GET on protected endpoint redirects to login.
from django.test import Client
c = Client()
resp = c.get('{endpoint}')
EVIDENCE['checks']['login_required_{endpoint}'] = {{
    'status_code': resp.status_code,
    'location': resp.headers.get('Location', ''),
    'pass': resp.status_code in (301, 302) and '/accounts/login' in resp.headers.get('Location', '')
}}

