# Verify migrations are up-to-date for app.
import subprocess
proc = subprocess.run(
    ['python', 'manage.py', 'showmigrations', '--plan', '{app}'],
    capture_output=True, text=True, timeout=60
)
unapplied = [line for line in (proc.stdout or '').splitlines() if '[ ]' in line]
EVIDENCE['checks']['migrations_{app}'] = {{
    'unapplied_count': len(unapplied),
    'returncode': proc.returncode,
    'pass': proc.returncode == 0 and len(unapplied) == 0
}}

